import React, { useState } from "react";
import axios from "axios";
import { FaKey } from "react-icons/fa";
import { useNavigate } from "react-router-dom";
import "./verifyotp.css";

const VerifyOtpPage = () => {
  const [otp, setOtp] = useState("");
  const [otpMessage, setOtpMessage] = useState("");
  const [otpError, setOtpError] = useState("");
  const [isSubmitting, setIsSubmitting] = useState(false);

  const navigate = useNavigate();
  const userEmail = localStorage.getItem("resetEmail");

  const handleOtpVerification = async (e) => {
    e.preventDefault();
    setOtpMessage("");
    setOtpError("");

    if (!otp.trim()) {
      setOtpError("OTP is required.");
      return;
    }

    try {
      setIsSubmitting(true);
      console.log("Verifying OTP...");

      const response = await axios.post("http://localhost:5000/api/auth/verify-otp", {
        email: userEmail,
        otp,
      });

      console.log("Response:", response.data);

      if (response.data?.success) {
        setOtpMessage(response.data.message || "OTP verified successfully!");

        localStorage.setItem("otpVerified", "true");

        setTimeout(() => navigate("/reset-password"), 1000);
      } else {
        setOtpError(response.data.message || "Invalid OTP.");
      }
    } catch (err) {
      setOtpError("Error verifying OTP. Please try again.");
      console.error("Verify OTP Error:", err);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="verify-otp-container">
      <img src="/assets/ODCSE Logo.png" alt="Logo" className="logo" />

      <form onSubmit={handleOtpVerification} className="verify-otp-form">
        <h2>Verify OTP</h2>
        <p>Enter the OTP sent to your registered email</p>

        <div className="input-group">
          <FaKey className="icon" />
          <input
            type="text"
            placeholder="Enter OTP"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            required
            disabled={isSubmitting}
          />
        </div>

        <button type="submit" className="verify-otp-button" disabled={isSubmitting}>
          {isSubmitting ? "Verifying..." : "Verify OTP"}
        </button>

        <div className="message-container">
          {otpMessage && <p className="success-message">{otpMessage}</p>}
          {otpError && <p className="error-message">{otpError}</p>}
        </div>
      </form>

      <div className="back-to-login">
        <button onClick={() => navigate("/forgot-password")} className="back-button">Back</button>
      </div>
    </div>
  );
};

export default VerifyOtpPage;
